interface AIStudio {
  hasSelectedApiKey: () => Promise<boolean>;
  openSelectKey: () => Promise<void>;
}

/**
 * Augment the global Window interface to include the aistudio object.
 * We use the 'readonly' modifier here because system-injected globals on the window 
 * object are typically defined as readonly in the underlying environment, and 
 * TypeScript requires all merged declarations of a property to have identical modifiers.
 */
interface Window {
  readonly aistudio: AIStudio;
}

