                    <h3 className="mt-2 text-sm font-semibold text-slate-900 dark:text-white">Tidak ada aduan ditemukan</h3>
                    <p className="mt-1 text-sm text-slate-500 dark:text-slate-400">Coba ubah kata kunci atau filter status.</p>
                    {isFiltered && (
