                 title="Reset Filter"
               >
                 <RotateCcw size={16} />
                 <span className="hidden lg:inline">Reset</span>
               </button>
             )}
          </div>
        </div>

        {/* Table Content */}
        <div className="flex-1 overflow-auto">
          <table className="min-w-full divide-y divide-slate-200 dark:divide-slate-700 relative">
            <thead className="bg-slate-50 dark:bg-slate-900/50 sticky top-0 z-10 shadow-sm">
              <tr>
                <th 
                  scope="col" 
                  className="px-6 py-3 text-left text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider cursor-pointer group hover:text-blue-600 dark:hover:text-blue-400 transition-colors select-none"
                  onClick={handleSortByDate}
                >
                  <div className="flex items-center gap-1.5">
                    Tiket / Tanggal
                    <div className="flex flex-col">
                      {sortDirection === 'asc' ? (
                        <ArrowUp size={14} className="text-blue-600 dark:text-blue-400" />
