                {item.icon}
              </span>
              {!isCollapsed && (
                <span className="truncate animate-in fade-in duration-300">
                  {item.name}
                </span>
              )}
            </Link>
          ))}
        </nav>

        <div className="px-4 py-4 border-t border-slate-200 dark:border-slate-800 space-y-2 mt-auto">
          {/* Theme Toggle Button */}
          <button
            onClick={toggleTheme}
            title={isCollapsed ? (theme === 'light' ? 'Mode Gelap' : 'Mode Terang') : ''}
            className="w-full flex items-center px-3 py-3 text-sm font-medium rounded-xl text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors"
          >
             {theme === 'light' ? (
               <>
                 <Moon size={20} className={`${isCollapsed ? 'mx-auto' : 'mr-3'} text-slate-500`} />
                 {!isCollapsed && <span className="animate-in fade-in duration-300">Mode Gelap</span>}
               </>
             ) : (
               <>
                 <Sun size={20} className={`${isCollapsed ? 'mx-auto' : 'mr-3'} text-amber-400`} />
                 {!isCollapsed && <span className="animate-in fade-in duration-300">Mode Terang</span>}
               </>
             )}
          </button>

          <Link 
            to="/admin/settings" 
            title={isCollapsed ? 'Pengaturan' : ''}
            className="flex items-center px-3 py-3 text-sm font-medium rounded-xl text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 hover:text-slate-900 dark:hover:text-white transition-colors"
          >
             <Settings size={20} className={`${isCollapsed ? 'mx-auto' : 'mr-3'} text-slate-500`} />
             {!isCollapsed && <span className="animate-in fade-in duration-300">Pengaturan</span>}
          </Link>
          <Link 
            to="/" 
            title={isCollapsed ? 'Keluar' : ''}
            className="flex items-center px-3 py-3 text-sm font-medium rounded-xl text-red-600 dark:text-red-400 hover:bg-red-50 dark:hover:bg-red-900/20 transition-colors"
          >
             <LogOut size={20} className={`${isCollapsed ? 'mx-auto' : 'mr-3'}`} />
             {!isCollapsed && <span className="animate-in fade-in duration-300">Keluar</span>}
          </Link>
        </div>
      </div>
    </div>
  );
};

