import React from 'react';
import { ComplaintStatus, PriorityLevel } from '../types';

interface StatusBadgeProps {
  status?: ComplaintStatus;
  priority?: PriorityLevel;
  className?: string;
}

const StatusBadge: React.FC<StatusBadgeProps> = ({ status, priority, className = '' }) => {
  if (status) {
    let colorClass = 'bg-gray-100 text-gray-800 dark:bg-slate-800 dark:text-slate-300';
    if (status === ComplaintStatus.PENDING) colorClass = 'bg-orange-100 text-orange-800 dark:bg-orange-900/40 dark:text-orange-300';
    if (status === ComplaintStatus.REJECTED) colorClass = 'bg-red-100 text-red-800 dark:bg-red-900/40 dark:text-red-300';
    if (status === ComplaintStatus.COMPLETED) colorClass = 'bg-green-100 text-green-800 dark:bg-green-900/40 dark:text-green-300';

    return (
      <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-[10px] font-black uppercase tracking-wider border border-transparent dark:border-white/5 ${colorClass} ${className}`}>
        {status}
      </span>
    );
  }

  if (priority) {
    let colorClass = 'bg-gray-100 text-gray-800 dark:bg-slate-800 dark:text-slate-300';
    if (priority === PriorityLevel.LOW) colorClass = 'bg-green-100 text-green-800 dark:bg-green-900/40 dark:text-green-300';
    if (priority === PriorityLevel.MEDIUM) colorClass = 'bg-blue-100 text-blue-800 dark:bg-blue-900/40 dark:text-blue-300';
    if (priority === PriorityLevel.HIGH) colorClass = 'bg-orange-100 text-orange-800 dark:bg-orange-900/40 dark:text-orange-300';
    if (priority === PriorityLevel.CRITICAL) colorClass = 'bg-red-100 text-red-800 dark:bg-red-900/40 dark:text-red-300';

    return (
      <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-[10px] font-black uppercase tracking-wider border border-transparent dark:border-white/5 ${colorClass} ${className}`}>
        {priority}
      </span>
    );
  }

  return null;
};

export default StatusBadge;

import React, { useEffect, useRef, useState } from 'react';
import maplibregl from 'maplibre-gl';
import AdminLayout from './AdminLayout';
import { MOCK_COMPLAINTS } from '../../constants';
import { ComplaintStatus } from '../../types';
import { AlertCircle, RefreshCw } from 'lucide-react';

const MapDistribution: React.FC = () => {
  const mapContainer = useRef<HTMLDivElement>(null);
  const map = useRef<maplibregl.Map | null>(null);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (map.current || !mapContainer.current) return;

    try {
      (maplibregl as any).workerUrl = "https://unpkg.com/maplibre-gl@4.0.0/dist/maplibre-gl-csp-worker.js";
    } catch (e) {
      console.warn("Failed to set workerUrl manually:", e);
    }

    try {
      const simpleStyle = {
        "version": 8,
        "sources": {
          "osm": {
            "type": "raster",
            "tiles": ["https://tile.openstreetmap.org/{z}/{x}/{y}.png"],
            "tileSize": 256,
            "attribution": "&copy; <a href='https://www.openstreetmap.org/copyright'>OpenStreetMap</a> contributors",
            "maxzoom": 19
          }
        },
        "layers": [
          {
            "id": "osm",
            "type": "raster",
            "source": "osm"
          }
        ]
      };

      const mapInstance = new maplibregl.Map({
        container: mapContainer.current,
        style: simpleStyle as any,
        center: [114.5928, -3.3194],
        zoom: 13,
        attributionControl: false,
        hash: false,
      });

      map.current = mapInstance;
      mapInstance.addControl(new maplibregl.NavigationControl(), 'top-right');

      mapInstance.on('load', () => {
        MOCK_COMPLAINTS.forEach((complaint) => {
          // New Simplified Color Mapping
          let color = '#f97316'; // Amber for PENDING (Belum dikerjakan)
          if (complaint.status === ComplaintStatus.REJECTED) color = '#ef4444'; // Red for REJECTED (Tidak diterima)
          if (complaint.status === ComplaintStatus.COMPLETED) color = '#22c55e'; // Green for COMPLETED (Selesai dikerjakan)

          const el = document.createElement('div');
          el.className = 'marker';
          el.style.width = '24px';
          el.style.height = '24px';
          el.style.backgroundColor = color;
          el.style.borderRadius = '50%';
          el.style.border = '2px solid white';
          el.style.boxShadow = '0 2px 4px rgba(0,0,0,0.3)';
          el.style.cursor = 'pointer';

          new maplibregl.Marker({ element: el })
            .setLngLat([complaint.lng, complaint.lat])
            .setPopup(
              new maplibregl.Popup({ offset: 25, closeButton: false }).setHTML(`
                <div style="font-family: 'Inter', sans-serif; padding: 10px; color: #1e293b; min-width: 200px;">
                  <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 6px;">
                     <span style="font-weight: 800; font-size: 14px; color: #0f172a; font-family: monospace;">${complaint.ticketNumber}</span>
                  </div>
                  <p style="margin-bottom: 4px; font-size: 11px; color: #64748b; font-weight: 700; text-transform: uppercase; letter-spacing: 0.025em;">${complaint.category}</p>
                  <p style="margin-bottom: 8px; font-size: 12px; color: #334155;">${complaint.location}</p>
                  <div style="padding-top: 8px; border-top: 1px solid #e2e8f0; display: flex; align-items: center; gap: 6px;">
                    <div style="width: 8px; height: 8px; border-radius: 50%; background-color: ${color};"></div>
                    <span style="font-size: 11px; font-weight: 800; color: #1e293b; text-transform: uppercase;">
                      ${complaint.status}
                    </span>
                  </div>
                </div>
              `)
            )
            .addTo(mapInstance);
        });
      });

      mapInstance.on('error', (e) => {
          console.error("Map internal error:", e);
          if (e.error && e.error.message && (e.error.message.includes('webgl') || e.error.message.includes('support'))) {
             setError("WebGL tidak didukung atau terjadi kesalahan grafis.");
          }
      });

    } catch (err: any) {
      console.error("Error initializing map:", err);
      setError(err.message || "Gagal memuat peta.");
    }

    return () => {
        if(map.current) {
            map.current.remove();
            map.current = null;
        }
    }
  }, []);

  return (
    <AdminLayout title="Peta Sebaran Kerusakan">
      <div className="bg-white dark:bg-slate-800 shadow-sm rounded-2xl border border-slate-100 dark:border-slate-700 p-4 h-[calc(100vh-180px)] flex flex-col relative">

        {/* Simplified Legend Mapping to Requested Categories */}
        <div className="flex flex-wrap justify-between items-center mb-4 gap-4 bg-slate-50 dark:bg-slate-900/50 p-3 rounded-xl">
            <div className="flex flex-wrap gap-4 text-xs font-black uppercase tracking-wider text-slate-600 dark:text-slate-400">
                <div className="flex items-center"><span className="w-3 h-3 rounded-full bg-red-500 mr-2 border border-white dark:border-slate-700"></span>Tidak diterima</div>
                <div className="flex items-center"><span className="w-3 h-3 rounded-full bg-orange-500 mr-2 border border-white dark:border-slate-700"></span>Belum dikerjakan</div>
                <div className="flex items-center"><span className="w-3 h-3 rounded-full bg-green-500 mr-2 border border-white dark:border-slate-700"></span>Selesai dikerjakan</div>
            </div>
            <div className="hidden sm:block text-slate-400 dark:text-slate-500 text-[10px] font-bold uppercase tracking-widest">
                *Banjarmasin Maju Sejahtera
            </div>
        </div>

        <div className="flex-1 rounded-xl border border-slate-200 dark:border-slate-700 overflow-hidden relative bg-slate-100 dark:bg-slate-900">
            {error ? (
                <div className="absolute inset-0 flex flex-col items-center justify-center text-center p-6">
                    <div className="bg-red-50 dark:bg-red-900/20 p-4 rounded-full mb-4">
                        <AlertCircle className="w-8 h-8 text-red-500 dark:text-red-400" />
                    </div>
                    <h3 className="text-lg font-bold text-slate-800 dark:text-white mb-2">Peta Bermasalah</h3>
                    <p className="text-slate-500 dark:text-slate-400 max-w-xs text-sm mb-4">{error}</p>
                    <button onClick={() => window.location.reload()} className="flex items-center px-4 py-2 bg-white dark:bg-slate-800 border border-slate-300 dark:border-slate-600 rounded-lg text-sm font-medium hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors">
                        <RefreshCw className="w-4 h-4 mr-2" /> Muat Ulang
                    </button>
                </div>
            ) : (
                <div ref={mapContainer} className="w-full h-full" />
            )}
        </div>
      </div>
    </AdminLayout>
  );
};

export default MapDistribution;

import React, { useState, useMemo } from 'react';
import AdminLayout from './AdminLayout';
import { MOCK_COMPLAINTS } from '../../constants';
import { Complaint, ComplaintStatus } from '../../types';
import StatusBadge from '../../components/StatusBadge';
import { 
  Search, 
  Filter, 
  X, 
  MapPin, 
  Calendar, 
  User, 
  Image as ImageIcon, 
  Save, 
  CheckCircle2,
  Truck,
  Banknote,
  RotateCcw,
  ArrowUp,
  ArrowDown,
  ArrowUpDown,
  ChevronDown
} from 'lucide-react';

const ComplaintList: React.FC = () => {
  const [complaints, setComplaints] = useState<Complaint[]>(MOCK_COMPLAINTS);
  const [toast, setToast] = useState<{ message: string; visible: boolean } | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('ALL');
  const [sortDirection, setSortDirection] = useState<'asc' | 'desc' | null>(null);
  const [selectedComplaint, setSelectedComplaint] = useState<Complaint | null>(null);
  const [isDetailOpen, setIsDetailOpen] = useState(false);
  const [isProcessOpen, setIsProcessOpen] = useState(false);

  const [processForm, setProcessForm] = useState({
    status: ComplaintStatus.PENDING,
    assignedTeam: '',
    estimatedCost: ''
  });

  const triggerToast = (message: string) => {
    setToast({ message, visible: true });
    setTimeout(() => {
      setToast(null);
    }, 3000);
  };

  const handleDetailClick = (complaint: Complaint) => {
    setSelectedComplaint(complaint);
    setIsDetailOpen(true);
  };

  const handleProcessClick = (complaint: Complaint) => {
    setSelectedComplaint(complaint);
    setProcessForm({
      status: complaint.status,
      assignedTeam: complaint.assignedTeam || '',
      estimatedCost: complaint.estimatedCost ? complaint.estimatedCost.toString() : ''
    });
    setIsProcessOpen(true);
  };

  const handleProcessSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedComplaint) return;

    const updatedComplaints = complaints.map(c => {
      if (c.id === selectedComplaint.id) {
        return {
          ...c,
          status: processForm.status,
          assignedTeam: processForm.assignedTeam,
          estimatedCost: processForm.estimatedCost ? parseInt(processForm.estimatedCost) : undefined,
          dateUpdated: new Date().toISOString()
        };
      }
      return c;
    });

    setComplaints(updatedComplaints);
    setIsProcessOpen(false);
    setSelectedComplaint(null);
    triggerToast('Aduan berhasil diperbarui');
  };

  const handleSortByDate = () => {
    if (sortDirection === null) setSortDirection('desc');
    else if (sortDirection === 'desc') setSortDirection('asc');
    else setSortDirection(null);
  };

  const resetFilters = () => {
    setSearchTerm('');
    setStatusFilter('ALL');
    setSortDirection(null);
  };

  const filteredComplaints = useMemo(() => {
    let result = complaints.filter(item => {
      const term = searchTerm.toLowerCase();
      const matchesSearch = 
        (item.ticketNumber?.toLowerCase().includes(term) ?? false) ||
        (item.location?.toLowerCase().includes(term) ?? false) ||
        (item.reporterName?.toLowerCase().includes(term) ?? false);
      const matchesFilter = statusFilter === 'ALL' || item.status === statusFilter;
      return matchesSearch && matchesFilter;
    });

    if (sortDirection) {
      result = [...result].sort((a, b) => {
        const dateA = new Date(a.dateSubmitted).getTime();
        const dateB = new Date(b.dateSubmitted).getTime();
        return sortDirection === 'asc' ? dateA - dateB : dateB - dateA;
      });
    }
    return result;
  }, [complaints, searchTerm, statusFilter, sortDirection]);

  const isFiltered = searchTerm !== '' || statusFilter !== 'ALL' || sortDirection !== null;

  return (
    <AdminLayout title="Manajemen Aduan">
      {toast?.visible && (
        <div className="fixed bottom-6 left-1/2 -translate-x-1/2 z-[100] bg-slate-900 dark:bg-slate-700 text-white px-6 py-3 rounded-2xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-bottom-4 duration-300">
          <CheckCircle2 className="w-5 h-5 text-green-400" />
          <span className="text-sm font-bold">{toast.message}</span>
        </div>
      )}

      <div className="bg-white dark:bg-slate-800 shadow-sm rounded-2xl border border-slate-100 dark:border-slate-700 overflow-hidden flex flex-col h-[calc(100vh-180px)]">
        <div className="p-4 border-b border-slate-100 dark:border-slate-700 bg-slate-50 dark:bg-slate-800/50 flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
          <div className="relative flex-1 max-w-lg">
             <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                <Search className="h-5 w-5 text-slate-400" />
             </div>
             <input 
               type="text" 
               value={searchTerm}
               onChange={(e) => setSearchTerm(e.target.value)}
               className="focus:ring-blue-500 focus:border-blue-500 block w-full pl-10 pr-10 sm:text-sm border-slate-300 dark:border-slate-600 rounded-xl p-2.5 bg-white dark:bg-slate-900 text-slate-900 dark:text-white placeholder-slate-400 transition-colors" 
               placeholder="Cari laporan..." 
             />
             {searchTerm && (
               <button onClick={() => setSearchTerm('')} className="absolute inset-y-0 right-0 pr-3 flex items-center text-slate-400 hover:text-slate-600 dark:hover:text-slate-200">
                 <X size={16} />
               </button>
             )}
          </div>

          <div className="flex items-center space-x-3">
             <div className="relative">
               <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                  <Filter className="h-4 w-4 text-slate-500 dark:text-slate-400" />
               </div>
               <select
                  value={statusFilter}
                  onChange={(e) => setStatusFilter(e.target.value)}
                  className="pl-9 pr-10 py-2.5 text-xs border border-slate-300 dark:border-slate-600 rounded-xl bg-white dark:bg-slate-900 text-slate-700 dark:text-slate-200 focus:ring-blue-500 focus:border-blue-500 appearance-none cursor-pointer hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors font-black uppercase tracking-wider"
               >
                 <option value="ALL">Semua Kategori</option>
                 <option value={ComplaintStatus.PENDING}>{ComplaintStatus.PENDING}</option>
                 <option value={ComplaintStatus.REJECTED}>{ComplaintStatus.REJECTED}</option>
                 <option value={ComplaintStatus.COMPLETED}>{ComplaintStatus.COMPLETED}</option>
               </select>
               <div className="absolute inset-y-0 right-0 flex items-center pr-3 pointer-events-none text-slate-400">
                  <ChevronDown size={14} />
               </div>
             </div>
             {isFiltered && (
               <button onClick={resetFilters} className="flex items-center gap-2 px-3 py-2.5 text-xs font-black uppercase tracking-wider text-slate-600 dark:text-slate-400 hover:text-blue-600 dark:hover:text-blue-400 transition-colors bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-xl shadow-sm">
                 <RotateCcw size={16} />
                 <span className="hidden lg:inline">Reset</span>
               </button>
             )}
          </div>
        </div>

        <div className="flex-1 overflow-auto">
          <table className="min-w-full divide-y divide-slate-200 dark:divide-slate-700 relative">
            <thead className="bg-slate-50 dark:bg-slate-900/50 sticky top-0 z-10 shadow-sm">
              <tr>
                <th scope="col" className="px-6 py-3 text-left text-[10px] font-black text-slate-500 dark:text-slate-400 uppercase tracking-widest cursor-pointer group hover:text-blue-600 transition-colors" onClick={handleSortByDate}>
                  <div className="flex items-center gap-1.5">Tiket / Tgl {sortDirection && (sortDirection === 'asc' ? <ArrowUp size={12}/> : <ArrowDown size={12}/>)}</div>
                </th>
                <th scope="col" className="px-6 py-3 text-left text-[10px] font-black text-slate-500 dark:text-slate-400 uppercase tracking-widest">Objek & Lokasi</th>
                <th scope="col" className="px-6 py-3 text-left text-[10px] font-black text-slate-500 dark:text-slate-400 uppercase tracking-widest">Kategori Aduan</th>
                <th scope="col" className="px-6 py-3 text-left text-[10px] font-black text-slate-500 dark:text-slate-400 uppercase tracking-widest text-right">Aksi</th>
              </tr>
            </thead>
            <tbody className="bg-white dark:bg-slate-800 divide-y divide-slate-200 dark:divide-slate-700">
              {filteredComplaints.map((complaint) => (
                <tr key={complaint.id} className="hover:bg-slate-50 dark:hover:bg-slate-700/30 transition-colors">
                  <td className="px-6 py-4 whitespace-nowrap">
                    <div className="text-xs font-black text-blue-600 dark:text-blue-400 font-mono tracking-wider">{complaint.ticketNumber}</div>
                    <div className="text-[10px] text-slate-500 dark:text-slate-400 mt-1 uppercase font-bold">{new Date(complaint.dateSubmitted).toLocaleDateString('id-ID')}</div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="text-xs font-black text-slate-900 dark:text-white uppercase tracking-tight">{complaint.category}</div>
                    <div className="text-xs text-slate-500 dark:text-slate-400 mt-0.5 truncate max-w-[200px]">{complaint.location}</div>
                  </td>
                  <td className="px-6 py-4 whitespace-nowrap"><StatusBadge status={complaint.status} /></td>
                  <td className="px-6 py-4 whitespace-nowrap text-right space-x-3">
                    <button onClick={() => handleDetailClick(complaint)} className="text-[11px] font-black text-blue-600 dark:text-blue-400 uppercase tracking-widest hover:underline">Detail</button>
                    <button onClick={() => handleProcessClick(complaint)} className="text-[11px] font-black text-green-600 dark:text-green-400 uppercase tracking-widest hover:underline">Update</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {isDetailOpen && selectedComplaint && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4"><div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={() => setIsDetailOpen(false)}></div>
          <div className="relative w-full max-w-2xl bg-white dark:bg-slate-800 rounded-3xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
            <div className="px-6 py-5 border-b border-slate-200 dark:border-slate-700 flex justify-between items-center bg-slate-50 dark:bg-slate-900/50">
               <h3 className="text-lg font-black text-slate-900 dark:text-white uppercase tracking-tight">Detail Aduan: {selectedComplaint.ticketNumber}</h3>
