            </div>

            <div className="mt-6 flex gap-2 justify-end border-t border-slate-50 dark:border-slate-700 pt-4 opacity-0 group-hover:opacity-100 transition-opacity">
              <button onClick={() => openEditModal(item)} className="p-2 text-slate-400 hover:text-blue-600"><Pencil size={14}/></button>
              <button onClick={() => executeDelete(item.id)} className="p-2 text-slate-400 hover:text-red-600"><Trash2 size={14}/></button>
            </div>
          </div>
        ))}
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={() => setIsModalOpen(false)}></div>
          <div className="relative w-full max-w-md bg-white dark:bg-slate-800 rounded-2xl p-6 shadow-2xl animate-in zoom-in-95">
             <h3 className="text-lg font-black uppercase mb-6 text-slate-900 dark:text-white">{isEditing ? 'Edit' : 'Tambah'} Alat</h3>
             <form onSubmit={handleSave} className="space-y-4">
                <div><label className="text-[10px] font-black text-slate-500 uppercase">Nama Alat/Kendaraan</label><input type="text" required value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} className="w-full mt-1 rounded-xl border-slate-300 dark:border-slate-600 text-sm font-bold bg-white dark:bg-slate-900"/></div>
                <div><label className="text-[10px] font-black text-slate-500 uppercase">Tipe / Jenis</label><input type="text" required value={formData.type} onChange={e => setFormData({...formData, type: e.target.value})} className="w-full mt-1 rounded-xl border-slate-300 dark:border-slate-600 text-sm font-bold bg-white dark:bg-slate-900" placeholder="Contoh: Pemadat Aspal"/></div>
                <div className="grid grid-cols-2 gap-4">
                   <div><label className="text-[10px] font-black text-slate-500 uppercase">Kategori</label>
                      <select value={formData.category} onChange={e => setFormData({...formData, category: e.target.value as any})} className="w-full mt-1 rounded-xl border-slate-300 dark:border-slate-600 text-[10px] font-black uppercase tracking-tight h-11 bg-white dark:bg-slate-900">
                         <option value="Heavy">Alat Berat & Mobil</option>
                         <option value="Tool">Peralatan Pekerja</option>
                      </select>
                   </div>
                   <div><label className="text-[10px] font-black text-slate-500 uppercase">Status</label>
                      <select value={formData.status} onChange={e => setFormData({...formData, status: e.target.value as any})} className="w-full mt-1 rounded-xl border-slate-300 dark:border-slate-600 text-[10px] font-black uppercase tracking-tight h-11 bg-white dark:bg-slate-900">
                         <option value="Tersedia">Tersedia</option>
                         <option value="Dipakai">Sedang Dipakai</option>
                         <option value="Perbaikan">Rusak / Servis</option>
                      </select>
                   </div>
                </div>
                <div className="pt-4 flex gap-3"><button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 py-3 text-[10px] font-black uppercase text-slate-500">Batal</button><button type="submit" className="flex-1 py-3 text-[10px] font-black uppercase bg-blue-600 text-white rounded-xl shadow-lg">Simpan</button></div>
             </form>
          </div>
        </div>
      )}
    </AdminLayout>
  );
};

