                  </div>
                  <div className="flex items-center gap-8">
                    <div className="text-right">
                       <p className={`text-2xl font-black ${item.currentStock === 0 ? 'text-red-600 animate-pulse' : isCritical ? 'text-orange-600' : 'text-slate-900 dark:text-white'}`}>{item.currentStock}</p>
                       <p className="text-[9px] text-slate-400 font-black uppercase tracking-widest">{item.unit}</p>
                    </div>
                    <div className="flex gap-2">
                       <button onClick={() => openEditModal(item)} className="p-2 text-slate-400 hover:text-blue-600 transition-colors"><Pencil size={14}/></button>
                       <button onClick={() => setItemToDelete({id: item.id, name: item.name})} className="p-2 text-slate-400 hover:text-red-600 transition-colors"><Trash2 size={14}/></button>
                    </div>
                  </div>
                </div>
              </li>
            );
          })}
        </ul>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={() => setIsModalOpen(false)}></div>
          <div className="relative w-full max-w-md bg-white dark:bg-slate-800 rounded-2xl p-6 shadow-2xl animate-in zoom-in-95">
             <h3 className="text-lg font-black uppercase mb-6 text-slate-900 dark:text-white">{isEditing ? 'Edit' : 'Tambah'} Material</h3>
             <form onSubmit={handleSave} className="space-y-4">
                <div><label className="text-[10px] font-black text-slate-500 uppercase">Nama Material</label><input type="text" required value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} className="w-full mt-1 rounded-xl border-slate-300 dark:border-slate-600 text-sm font-bold bg-white dark:bg-slate-900"/></div>
                <div className="grid grid-cols-2 gap-4">
                  <div><label className="text-[10px] font-black text-slate-500 uppercase">Stok</label><input type="number" required value={formData.currentStock} onChange={e => setFormData({...formData, currentStock: Number(e.target.value)})} className="w-full mt-1 rounded-xl border-slate-300 dark:border-slate-600 text-sm font-bold bg-white dark:bg-slate-900"/></div>
                  <div><label className="text-[10px] font-black text-slate-500 uppercase">Satuan</label><input type="text" required value={formData.unit} onChange={e => setFormData({...formData, unit: e.target.value})} className="w-full mt-1 rounded-xl border-slate-300 dark:border-slate-600 text-sm font-bold bg-white dark:bg-slate-900"/></div>
                </div>
                <div><label className="text-[10px] font-black text-slate-500 uppercase">Batas Minimum</label><input type="number" required value={formData.currentStock} onChange={e => setFormData({...formData, minThreshold: Number(e.target.value)})} className="w-full mt-1 rounded-xl border-slate-300 dark:border-slate-600 text-sm font-bold bg-white dark:bg-slate-900"/></div>
                <div className="pt-4 flex gap-3"><button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 py-3 text-[10px] font-black uppercase text-slate-500">Batal</button><button type="submit" className="flex-1 py-3 text-[10px] font-black uppercase bg-blue-600 text-white rounded-xl shadow-lg">Simpan</button></div>
             </form>
          </div>
        </div>
      )}

      {itemToDelete && (
        <div className="fixed inset-0 z-[70] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={() => setItemToDelete(null)}></div>
          <div className="relative w-full max-sm bg-white dark:bg-slate-800 rounded-2xl p-6 shadow-2xl">
             <h3 className="text-lg font-black uppercase text-slate-900 dark:text-white mb-4">Hapus Material?</h3>
             <p className="text-sm text-slate-500 mb-6">Anda akan menghapus material "{itemToDelete.name}".</p>
             <div className="flex gap-3"><button onClick={() => setItemToDelete(null)} className="flex-1 py-3 text-[10px] font-black uppercase">Batal</button><button onClick={executeDelete} className="flex-1 py-3 text-[10px] font-black uppercase bg-red-600 text-white rounded-xl">Hapus</button></div>
          </div>
        </div>
      )}
    </AdminLayout>
  );
};

