  const [activeTab, setActiveTab] = useState<RoadType>(RoadType.JALAN);
  const [selectedMonth, setSelectedMonth] = useState('2024-03');
  const [selectedWeek, setSelectedWeek] = useState(1);
  const [workers, setWorkers] = useState<Worker[]>(MOCK_WORKERS);
  const [attendance, setAttendance] = useState<AttendanceRecord[]>(MOCK_ATTENDANCE);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [selectedWorkerId, setSelectedWorkerId] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [formData, setFormData] = useState({
    name: '',
    category: RoadType.JALAN,
    dailyRate: 150000,
    otRate: 75000,
    monday: 0,
    tuesday: 0,
    wednesday: 0,
    thursday: 0,
    friday: 0,
    saturday: 0,
    sunday: 0
  });

  // --- Calculations ---
  const filteredWorkers = useMemo(() => workers.filter(w => w.category === activeTab), [workers, activeTab]);

  const calculateWage = (record: AttendanceRecord, worker: Worker) => {
    const presence = record.presence;
    const days = Object.values(presence);
    const standardDays = days.filter(d => d === 1).length;
    const overtimeDays = days.filter(d => d === 2).length;
    return (standardDays * worker.dailyRate) + (overtimeDays * (worker.dailyRate + worker.otRate));
  };

  const getAttendanceForWorker = (workerId: string) => {
    return attendance.find(a => a.workerId === workerId && a.month === selectedMonth && a.week === selectedWeek);
  };

  const totalWeeklyWage = useMemo(() => {
    return filteredWorkers.reduce((acc, worker) => {
      const record = getAttendanceForWorker(worker.id);
      return acc + (record ? calculateWage(record, worker) : 0);
    }, 0);
  }, [filteredWorkers, attendance, selectedMonth, selectedWeek]);

  const chartData = useMemo(() => {
    const days = ['monday', 'tuesday', 'wednesday', 'thursday', 'friday', 'saturday', 'sunday'];
    return days.map(day => {
      const count = attendance.filter(a => 
        a.month === selectedMonth && 
        a.week === selectedWeek && 
        (a.presence as any)[day] > 0
      ).length;
      return { name: day.substring(0, 3).toUpperCase(), count };
    });
  }, [attendance, selectedMonth, selectedWeek]);

  // --- Excel Operations ---
  const handleExport = () => {
    const dataToExport = filteredWorkers.map((worker, index) => {
      const record = getAttendanceForWorker(worker.id);
      return {
        'Pekan': selectedWeek,
        'No': index + 1,
        'Nama Pekerja': worker.name,
        'Senin': record?.presence.monday || 0,
        'Selasa': record?.presence.tuesday || 0,
        'Rabu': record?.presence.wednesday || 0,
        'Kamis': record?.presence.thursday || 0,
        'Jumat': record?.presence.friday || 0,
        'Sabtu': record?.presence.saturday || 0,
        'Minggu': record?.presence.sunday || 0,
        'Total Upah': record ? calculateWage(record, worker) : 0
      };
    });

    const worksheet = XLSX.utils.json_to_sheet(dataToExport);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, 'Rekap Presensi');
    XLSX.writeFile(workbook, `Presensi_${activeTab}_Pekan${selectedWeek}_${selectedMonth}.xlsx`);
  };

  const downloadTemplate = () => {
    const template = [
      {
        'Pekan': 1,
        'Nama Pekerja': 'Ahmad Fulan',
        'Kategori': 'Jalan',
        'Upah Harian': 150000,
        'Upah Lembur': 75000,
        'Senin': 1, 'Selasa': 1, 'Rabu': 1, 'Kamis': 1, 'Jumat': 1, 'Sabtu': 2, 'Minggu': 0
      },
      {
        'Pekan': 2,
        'Nama Pekerja': 'Ahmad Fulan',
        'Kategori': 'Jalan',
        'Upah Harian': 150000,
        'Upah Lembur': 75000,
        'Senin': 1, 'Selasa': 1, 'Rabu': 1, 'Kamis': 1, 'Jumat': 1, 'Sabtu': 1, 'Minggu': 0
      }
    ];
    const worksheet = XLSX.utils.json_to_sheet(template);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, 'Template Import');
    XLSX.writeFile(workbook, 'Template_MultiPekan_Tenaga_Kerja.xlsx');
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const bstr = event.target?.result;
        const workbook = XLSX.read(bstr, { type: 'binary' });
        const sheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[sheetName];
        const data = XLSX.utils.sheet_to_json(worksheet) as any[];

        const newWorkersMap = new Map<string, Worker>();
        const newRecords: AttendanceRecord[] = [];

        data.forEach((row, i) => {
          // Normalize names as potential IDs if not provided
          const name = row['Nama Pekerja'] || `Pekerja-${i}`;
          const cat = row['Kategori']?.toLowerCase().includes('jembatan') ? RoadType.JEMBATAN : RoadType.JALAN;
          const weekFromRow = Number(row['Pekan']) || selectedWeek;

          // Only add worker to list once based on name
          if (!newWorkersMap.has(name)) {
            newWorkersMap.set(name, {
              id: `imp-${name.replace(/\s+/g, '-').toLowerCase()}`,
              name: name,
              category: cat,
              dailyRate: Number(row['Upah Harian']) || 150000,
              otRate: Number(row['Upah Lembur']) || 75000
            });
          }

          const currentWorker = newWorkersMap.get(name)!;

          newRecords.push({
            id: `rec-${Date.now()}-${i}`,
            workerId: currentWorker.id,
            month: selectedMonth,
            week: weekFromRow,
            presence: {
              monday: Number(row['Senin']) || 0,
              tuesday: Number(row['Selasa']) || 0,
              wednesday: Number(row['Rabu']) || 0,
              thursday: Number(row['Kamis']) || 0,
              friday: Number(row['Jumat']) || 0,
              saturday: Number(row['Sabtu']) || 0,
              sunday: Number(row['Minggu']) || 0
            }
          });
        });

        // Merge Workers (prevent duplicates)
        setWorkers(prev => {
          const existingNames = new Set(prev.map(w => w.name));
          const trulyNewWorkers = Array.from(newWorkersMap.values()).filter(w => !existingNames.has(w.name));
          return [...prev, ...trulyNewWorkers];
        });

        // Merge Attendance Records (Overwrite if same worker/month/week exists)
        setAttendance(prev => {
          const existing = [...prev];
          newRecords.forEach(nr => {
            const idx = existing.findIndex(e => e.workerId === nr.workerId && e.month === nr.month && e.week === nr.week);
            if (idx > -1) existing[idx] = nr;
            else existing.push(nr);
          });
          return existing;
        });

        alert(`Berhasil mengimpor data dari file. Data diproses untuk pekan-pekan yang tertera di kolom "Pekan".`);
      } catch (err) {
        console.error(err);
        alert('Gagal membaca file Excel. Pastikan format kolom "Pekan" dan "Nama Pekerja" tersedia.');
      } finally {
        setIsProcessing(false);
        if (fileInputRef.current) fileInputRef.current.value = '';
      }
    };
    reader.readAsBinaryString(file);
  };

  // --- CRUD Handlers ---
  const openModal = (worker?: Worker) => {
    if (worker) {
      setIsEditing(true);
      setSelectedWorkerId(worker.id);
      const record = getAttendanceForWorker(worker.id);
      setFormData({
        name: worker.name,
        category: worker.category,
        dailyRate: worker.dailyRate,
        otRate: worker.otRate,
        monday: record?.presence.monday || 0,
        tuesday: record?.presence.tuesday || 0,
        wednesday: record?.presence.wednesday || 0,
        thursday: record?.presence.thursday || 0,
        friday: record?.presence.friday || 0,
        saturday: record?.presence.saturday || 0,
        sunday: record?.presence.sunday || 0
      });
    } else {
      setIsEditing(false);
      setSelectedWorkerId(null);
      setFormData({
        name: '',
        category: activeTab,
        dailyRate: activeTab === RoadType.JALAN ? 150000 : 175000,
        otRate: activeTab === RoadType.JALAN ? 75000 : 85000,
        monday: 1, tuesday: 1, wednesday: 1, thursday: 1, friday: 1, saturday: 0, sunday: 0
      });
    }
    setIsModalOpen(true);
  };

  const handleDelete = (id: string) => {
    if (confirm('Hapus data pekerja ini?')) {
      setWorkers(workers.filter(w => w.id !== id));
      setAttendance(attendance.filter(a => a.workerId !== id));
    }
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    const workerId = selectedWorkerId || `w-${Date.now()}`;
    const newWorker: Worker = {
      id: workerId,
      name: formData.name,
      category: formData.category,
      dailyRate: Number(formData.dailyRate),
      otRate: Number(formData.otRate)
    };

    const newRecord: AttendanceRecord = {
      id: `a-${Date.now()}`,
      workerId: workerId,
      month: selectedMonth,
      week: selectedWeek,
      presence: {
        monday: formData.monday,
        tuesday: formData.tuesday,
        wednesday: formData.wednesday,
        thursday: formData.thursday,
        friday: formData.friday,
        saturday: formData.saturday,
        sunday: formData.sunday
      }
    };

    if (isEditing) {
      setWorkers(workers.map(w => w.id === workerId ? newWorker : w));
      setAttendance(prev => {
        const others = prev.filter(a => !(a.workerId === workerId && a.month === selectedMonth && a.week === selectedWeek));
        return [...others, newRecord];
      });
    } else {
      setWorkers([...workers, newWorker]);
      setAttendance([...attendance, newRecord]);
    }
    setIsModalOpen(false);
  };

  const renderCell = (val: number) => {
    if (val === 1) return <div className="w-8 h-8 rounded-lg bg-green-100 dark:bg-green-900/40 flex items-center justify-center text-green-700 dark:text-green-400 font-black text-xs">1</div>;
    if (val === 2) return <div className="w-8 h-8 rounded-lg bg-blue-100 dark:bg-blue-900/40 flex items-center justify-center text-blue-700 dark:text-blue-400 font-black text-xs">2</div>;
    return <div className="w-8 h-8 rounded-lg bg-slate-100 dark:bg-slate-800 flex items-center justify-center text-slate-300 dark:text-slate-600 font-black text-xs">-</div>;
  };

  return (
    <AdminLayout title="Manajemen Tenaga Kerja">

      {/* Metrics Summary */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
        <div className="bg-gradient-to-br from-blue-600 to-indigo-700 rounded-3xl p-6 text-white shadow-xl relative overflow-hidden group">
          <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:rotate-12 transition-transform"><Banknote size={80} /></div>
          <div className="relative z-10">
            <div className="flex justify-between items-start mb-4">
              <div className="p-3 bg-white/20 rounded-2xl backdrop-blur-md"><Banknote size={24}/></div>
              <span className="text-[10px] font-black uppercase bg-white/20 px-3 py-1 rounded-full backdrop-blur-md">Pekan {selectedWeek}</span>
            </div>
            <p className="text-[10px] font-black uppercase tracking-widest text-blue-100 mb-1">Total Upah {activeTab}</p>
            <h3 className="text-3xl font-black tabular-nums">Rp {totalWeeklyWage.toLocaleString('id-ID')}</h3>
            <div className="mt-4 flex items-center gap-2 text-blue-100 text-[10px] font-bold">
              <TrendingUp size={14}/> <span>Penggajian Terotomatisasi</span>
            </div>
          </div>
        </div>

        <div className="bg-white dark:bg-slate-800 rounded-3xl p-6 shadow-sm border border-slate-100 dark:border-slate-700 md:col-span-2">
           <div className="flex justify-between items-center mb-4">
              <h4 className="text-xs font-black uppercase tracking-widest text-slate-500">Statistik Kehadiran Mingguan</h4>
              <div className="flex items-center gap-4">
                 <div className="flex items-center gap-1.5"><span className="w-2 h-2 rounded-full bg-blue-600"></span><span className="text-[9px] font-black uppercase text-slate-400">Pekerja Hadir</span></div>
              </div>
           </div>
           <div className="h-28 w-full">
             <ResponsiveContainer width="100%" height="100%">
               <BarChart data={chartData}>
                 <Bar dataKey="count" fill="#3b82f6" radius={[4, 4, 0, 0]} />
                 <XAxis dataKey="name" hide />
                 <Tooltip cursor={{fill: 'transparent'}} contentStyle={{fontSize: '10px', borderRadius: '8px'}} />
               </BarChart>
             </ResponsiveContainer>
           </div>
        </div>
      </div>

      {/* Tabs & Filters */}
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-6 mb-8">
        <div className="flex p-1.5 bg-white dark:bg-slate-800 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-700 w-full lg:w-auto">
          <button 
            onClick={() => setActiveTab(RoadType.JALAN)}
            className={`flex-1 lg:flex-none flex items-center justify-center gap-2 px-8 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === RoadType.JALAN ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-800 dark:hover:text-slate-200'}`}
          >
            Pekerja Jalan
          </button>
          <button 
            onClick={() => setActiveTab(RoadType.JEMBATAN)}
            className={`flex-1 lg:flex-none flex items-center justify-center gap-2 px-8 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === RoadType.JEMBATAN ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-800 dark:hover:text-slate-200'}`}
          >
            Pekerja Jembatan
          </button>
        </div>

        <div className="flex flex-wrap gap-3 w-full lg:w-auto">
          <div className="flex items-center gap-2 bg-white dark:bg-slate-800 px-4 py-2.5 rounded-2xl border border-slate-100 dark:border-slate-700 shadow-sm flex-1 min-w-[140px]">
            <Calendar size={16} className="text-slate-400" />
            <input 
              type="month" 
              value={selectedMonth}
              onChange={(e) => setSelectedMonth(e.target.value)}
              className="bg-transparent border-none text-[11px] font-black uppercase tracking-tight outline-none text-slate-700 dark:text-slate-200"
            />
          </div>
          <div className="relative flex-1 min-w-[100px]">
            <select 
              value={selectedWeek}
              onChange={(e) => setSelectedWeek(Number(e.target.value))}
              className="w-full pl-4 pr-10 py-3 text-[11px] font-black uppercase border border-slate-100 dark:border-slate-700 rounded-2xl bg-white dark:bg-slate-800 text-slate-700 dark:text-slate-200 appearance-none outline-none shadow-sm"
            >
              <option value={1}>Pekan 1</option>
              <option value={2}>Pekan 2</option>
              <option value={3}>Pekan 3</option>
              <option value={4}>Pekan 4</option>
              <option value={5}>Pekan 5</option>
            </select>
            <ChevronDown size={14} className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" />
          </div>
          <button 
            onClick={() => openModal()}
            className="flex items-center justify-center gap-2 px-6 py-3 bg-blue-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-blue-600/20 active:scale-95 transition-all w-full lg:w-auto"
          >
            <Plus size={16}/> Tambah Pekerja
          </button>
        </div>
      </div>

      {/* Data Operations Toolbar */}
      <div className="mb-6 flex flex-col sm:flex-row justify-between items-center gap-4 bg-slate-50 dark:bg-slate-900/50 p-4 rounded-3xl border border-slate-200 dark:border-slate-700">
         <div className="flex items-center gap-3">
            <div className="p-2 bg-white dark:bg-slate-800 rounded-xl shadow-sm text-blue-600">
              <FileSpreadsheet size={20} />
            </div>
            <div>
               <h5 className="text-[10px] font-black uppercase tracking-widest text-slate-900 dark:text-white">Pengelolaan Data Excel (Multi-Pekan)</h5>
               <p className="text-[9px] text-slate-500 font-bold uppercase">Sertakan kolom "Pekan" untuk import banyak data sekaligus</p>
            </div>
         </div>
         <div className="flex flex-wrap items-center gap-3 w-full sm:w-auto">
            <button 
              onClick={handleExport}
              className="flex-1 sm:flex-none flex items-center justify-center gap-2 px-4 py-2.5 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl text-[9px] font-black uppercase tracking-widest text-slate-700 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-700 transition-all shadow-sm"
            >
               <Download size={14} /> Export Excel
            </button>
            <div className="flex-1 sm:flex-none relative">
               <input 
                 type="file" 
                 ref={fileInputRef}
                 onChange={handleImport}
                 accept=".xlsx, .xls"
                 className="hidden"
               />
               <button 
                 onClick={() => fileInputRef.current?.click()}
                 disabled={isProcessing}
                 className="w-full flex items-center justify-center gap-2 px-4 py-2.5 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl text-[9px] font-black uppercase tracking-widest text-slate-700 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-700 transition-all shadow-sm disabled:opacity-50"
               >
                  {isProcessing ? <Loader2 size={14} className="animate-spin" /> : <UploadCloud size={14} />} Import Excel
               </button>
            </div>
            <button 
              onClick={downloadTemplate}
              className="flex-1 sm:flex-none flex items-center justify-center gap-2 px-4 py-2.5 bg-blue-50 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-blue-100 dark:hover:bg-blue-900/50 transition-all"
            >
               <FileSpreadsheet size={14} /> Unduh Template
            </button>
         </div>
      </div>

      {/* Grid Table */}
      <div className="bg-white dark:bg-slate-800 rounded-3xl border border-slate-100 dark:border-slate-700 shadow-sm overflow-hidden animate-in fade-in duration-500">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50 dark:bg-slate-900/50 border-b border-slate-100 dark:border-slate-700">
                <th className="px-6 py-5 text-[10px] font-black uppercase tracking-widest text-slate-500 w-16">No</th>
                <th className="px-6 py-5 text-[10px] font-black uppercase tracking-widest text-slate-500">Nama Pekerja</th>
                <th className="px-3 py-5 text-[10px] font-black uppercase tracking-widest text-slate-500 text-center">Sen</th>
                <th className="px-3 py-5 text-[10px] font-black uppercase tracking-widest text-slate-500 text-center">Sel</th>
                <th className="px-3 py-5 text-[10px] font-black uppercase tracking-widest text-slate-500 text-center">Rab</th>
                <th className="px-3 py-5 text-[10px] font-black uppercase tracking-widest text-slate-500 text-center">Kam</th>
                <th className="px-3 py-5 text-[10px] font-black uppercase tracking-widest text-slate-500 text-center">Jum</th>
                <th className="px-3 py-5 text-[10px] font-black uppercase tracking-widest text-slate-500 text-center">Sab</th>
                <th className="px-3 py-5 text-[10px] font-black uppercase tracking-widest text-slate-500 text-center">Min</th>
                <th className="px-6 py-5 text-[10px] font-black uppercase tracking-widest text-slate-500 text-right">Upah Pekan {selectedWeek}</th>
                <th className="px-6 py-5 text-[10px] font-black uppercase tracking-widest text-slate-500 text-center">Aksi</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 dark:divide-slate-700">
              {filteredWorkers.map((worker, index) => {
                const record = getAttendanceForWorker(worker.id);
                const weeklyWage = record ? calculateWage(record, worker) : 0;
                return (
                  <tr key={worker.id} className="hover:bg-slate-50 dark:hover:bg-slate-700/30 transition-colors group">
                    <td className="px-6 py-5 text-xs font-bold text-slate-400">{index + 1}</td>
                    <td className="px-6 py-5">
                      <div className="text-sm font-black text-slate-900 dark:text-white uppercase tracking-tight">{worker.name}</div>
                      <div className="text-[9px] font-black text-slate-400 uppercase mt-0.5 tracking-wider">Rp {worker.dailyRate.toLocaleString()} / Hari</div>
                    </td>
                    <td className="px-3 py-5 text-center">{renderCell(record?.presence.monday || 0)}</td>
                    <td className="px-3 py-5 text-center">{renderCell(record?.presence.tuesday || 0)}</td>
                    <td className="px-3 py-5 text-center">{renderCell(record?.presence.wednesday || 0)}</td>
                    <td className="px-3 py-5 text-center">{renderCell(record?.presence.thursday || 0)}</td>
                    <td className="px-3 py-5 text-center">{renderCell(record?.presence.friday || 0)}</td>
                    <td className="px-3 py-5 text-center">{renderCell(record?.presence.saturday || 0)}</td>
                    <td className="px-3 py-5 text-center">{renderCell(record?.presence.sunday || 0)}</td>
                    <td className="px-6 py-5 text-right">
                       <span className="text-sm font-black text-slate-900 dark:text-white tabular-nums">Rp {weeklyWage.toLocaleString()}</span>
                    </td>
                    <td className="px-6 py-5">
                      <div className="flex items-center justify-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                         <button onClick={() => openModal(worker)} className="p-2 text-slate-400 hover:text-blue-600 transition-colors" title="Edit Presensi"><Pencil size={14}/></button>
                         <button onClick={() => handleDelete(worker.id)} className="p-2 text-slate-400 hover:text-red-600 transition-colors" title="Hapus"><Trash2 size={14}/></button>
                      </div>
                    </td>
                  </tr>
                );
              })}
              {filteredWorkers.length === 0 && (
                <tr>
                   <td colSpan={11} className="px-6 py-12 text-center text-slate-400 text-xs italic">Belum ada data pekerja untuk kategori ini.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>

        {/* Footer Info */}
        <div className="px-6 py-4 bg-slate-50 dark:bg-slate-900/50 border-t border-slate-100 dark:border-slate-700 flex flex-col md:flex-row justify-between items-center gap-4 text-[9px] font-black uppercase tracking-widest text-slate-400">
           <div className="flex gap-6">
              <div className="flex items-center gap-2"><div className="w-2.5 h-2.5 rounded-sm bg-green-500"></div> 1 = Hadir</div>
              <div className="flex items-center gap-2"><div className="w-2.5 h-2.5 rounded-sm bg-blue-500"></div> 2 = Lembur</div>
           </div>
           <div className="flex items-center gap-2 text-blue-600 dark:text-blue-400 bg-blue-50 dark:bg-blue-900/20 px-3 py-1 rounded-full border border-blue-100 dark:border-blue-800">
             <AlertTriangle size={10} /> 
             <span>Total upah dihitung otomatis dari presensi harian per pekan.</span>
           </div>
           <p className="hidden md:block">*Banjarmasin Maju Sejahtera</p>
        </div>
      </div>

      {/* CRUD Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={() => setIsModalOpen(false)}></div>
