                  </div>
                  <div>
                    <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1 block">Upah Harian (Rp)</label>
                    <input type="number" required value={formData.dailyRate} onChange={e => setFormData({...formData, dailyRate: Number(e.target.value)})} className="w-full px-4 py-3 rounded-2xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-sm font-bold outline-none focus:ring-2 focus:ring-blue-500"/>
                  </div>
                  <div>
                    <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1 block">Bonus Lembur (Rp)</label>
                    <input type="number" required value={formData.otRate} onChange={e => setFormData({...formData, otRate: Number(e.target.value)})} className="w-full px-4 py-3 rounded-2xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-sm font-bold outline-none focus:ring-2 focus:ring-blue-500"/>
                  </div>
               </div>

               <div>
                 <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-4 block">Presensi Harian (Kode: 0=Absen, 1=Hadir, 2=Lembur)</label>
                 <div className="grid grid-cols-7 gap-2">
                    {['monday', 'tuesday', 'wednesday', 'thursday', 'friday', 'saturday', 'sunday'].map(day => (
                      <div key={day} className="text-center">
                         <label className="text-[8px] font-black uppercase text-slate-400 mb-1 block">{day.substring(0,3)}</label>
                         <select 
                           value={(formData as any)[day]} 
                           onChange={e => setFormData({...formData, [day]: Number(e.target.value)})}
                           className="w-full px-2 py-2.5 rounded-xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-900 text-xs font-black text-center"
                         >
                            <option value={0}>0</option>
                            <option value={1}>1</option>
                            <option value={2}>2</option>
                         </select>
                      </div>
                    ))}
                 </div>
               </div>

               <div className="pt-4 flex gap-3">
                  <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 py-4 text-[10px] font-black uppercase text-slate-500">Batalkan</button>
                  <button type="submit" className="flex-1 py-4 bg-blue-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-blue-600/20 active:scale-95 transition-all">Simpan Data</button>
               </div>
            </form>
          </div>
        </div>
      )}

    </AdminLayout>
  );
};

